acsl:
admit \valid(a+(0 .. N-1));
admit \valid(b+(0 .. N-1));
admit \valid(c+(0 .. N-1));
admit \separated(a+(0 .. N-1), b+(0 .. N-1), c+(0 .. N-1));

loop invariant 1 <= i <= N;
loop invariant a[0] == 6;
loop invariant \forall integer j; 1 <= j < i ==> a[j] == 6*(j+1);
loop assigns i, a[1 .. N-1];
loop variant N - i;

loop invariant 1 <= i <= N;
loop invariant b[0] == 1;
loop invariant \forall integer j; 0 <= j < N ==> a[j] == 6*(j+1);
loop invariant \forall integer j; 1 <= j < i ==> b[j] == 1 + 3*j*(j+1);
loop assigns i, b[1 .. N-1];
loop variant N - i;

loop invariant 1 <= i <= N;
loop invariant c[0] == N;
loop invariant \forall integer j; 0 <= j < N ==> a[j] == 6*(j+1);
loop invariant \forall integer j; 0 <= j < N ==> b[j] == 1 + 3*j*(j+1);
loop invariant \forall integer j; 1 <= j < i ==> c[j] == N + j*j*j;
loop assigns i, c[1 .. N-1];
loop variant N - i;

loop invariant 0 <= i <= N;
loop invariant \forall integer j; 0 <= j < N ==> c[j] == N + j*j*j;
loop assigns i;
loop variant N - i;
